package main

import (
	"errors"
	"sort"
	"sync"
)

var (
	ErrNotFound = errors.New("not found")
	ErrExists   = errors.New("already exists")
	ErrInvalid  = errors.New("invalid")
)

// Task is the domain record filtered by the scenario tests.
type Task struct {
	ID     string
	Title  string
	Status string // "todo" | "doing" | "done"
}

func validStatus(s string) bool { return s == "todo" || s == "doing" || s == "done" }

// TaskService owns a goroutine-safe in-memory table of tasks.
type TaskService struct {
	mu    sync.RWMutex
	tasks map[string]Task
}

func NewTaskService() *TaskService {
	return &TaskService{tasks: make(map[string]Task)}
}

func (s *TaskService) Create(t Task) error {
	if t.ID == "" || t.Title == "" || !validStatus(t.Status) {
		return ErrInvalid
	}
	s.mu.Lock()
	defer s.mu.Unlock()
	if _, ok := s.tasks[t.ID]; ok {
		return ErrExists
	}
	s.tasks[t.ID] = t
	return nil
}

func (s *TaskService) Get(id string) (Task, error) {
	s.mu.RLock()
	defer s.mu.RUnlock()
	t, ok := s.tasks[id]
	if !ok {
		return Task{}, ErrNotFound
	}
	return t, nil
}

// List returns tasks filtered by status ("" = all), sorted by ID, capped at
// limit when limit > 0.
func (s *TaskService) List(status string, limit int) []Task {
	s.mu.RLock()
	defer s.mu.RUnlock()
	out := make([]Task, 0, len(s.tasks))
	for _, t := range s.tasks {
		if status != "" && t.Status != status {
			continue
		}
		out = append(out, t)
	}
	sort.Slice(out, func(i, j int) bool { return out[i].ID < out[j].ID })
	if limit > 0 && len(out) > limit {
		out = out[:limit]
	}
	return out
}

func main() {}
