package main

import "testing"

// Scenario/table test for a multi-entity service List with filters. THE RULE
// THAT KEEPS TABLE SUITES CONSISTENT: every row declares its OWN seed
// fixtures and derives its expectations from THAT seed only — no row assumes
// records created by another row, a shared setup block, or the impl's zero
// state. A fresh service is built INSIDE each subtest, the row's seed is
// created there, and wantIDs is literally readable from the row's own seed.
func TestListScenarios(t *testing.T) {
	seedAll := []Task{
		{ID: "t1", Title: "write spec", Status: "todo"},
		{ID: "t2", Title: "build api", Status: "doing"},
		{ID: "t3", Title: "ship it", Status: "done"},
		{ID: "t4", Title: "fix bug", Status: "todo"},
	}
	cases := []struct {
		name    string
		seed    []Task // fixtures THIS row creates for itself
		status  string // filter ("" = all)
		limit   int    // 0 = no cap
		wantIDs []string
	}{
		{name: "all tasks, no filter", seed: seedAll, status: "", limit: 0,
			wantIDs: []string{"t1", "t2", "t3", "t4"}},
		{name: "filter by todo", seed: seedAll, status: "todo", limit: 0,
			wantIDs: []string{"t1", "t4"}},
		{name: "filter by done", seed: seedAll, status: "done", limit: 0,
			wantIDs: []string{"t3"}},
		{name: "limit caps the result", seed: seedAll, status: "", limit: 2,
			wantIDs: []string{"t1", "t2"}},
		{name: "empty seed lists nothing", seed: nil, status: "todo", limit: 0,
			wantIDs: []string{}},
		{name: "filter misses every seed", seed: []Task{
			{ID: "x1", Title: "only todo here", Status: "todo"},
		}, status: "done", limit: 0, wantIDs: []string{}},
	}
	for _, tc := range cases {
		t.Run(tc.name, func(t *testing.T) {
			svc := NewTaskService() // FRESH service per row — no leakage
			for _, task := range tc.seed {
				if err := svc.Create(task); err != nil {
					t.Fatalf("seed Create(%q): %v", task.ID, err)
				}
			}
			got := svc.List(tc.status, tc.limit)
			if len(got) != len(tc.wantIDs) {
				t.Fatalf("List(%q, %d) returned %d tasks, want %d",
					tc.status, tc.limit, len(got), len(tc.wantIDs))
			}
			for i, want := range tc.wantIDs {
				if got[i].ID != want {
					t.Errorf("List(%q, %d)[%d].ID = %q, want %q",
						tc.status, tc.limit, i, got[i].ID, want)
				}
			}
		})
	}
}
